import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { provideIcons } from '@ng-icons/core';
import { phosphorFilePdf } from '@ng-icons/phosphor-icons/regular';

import { HbAttachmentImports, HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-attachment-basic',
  imports: [HbAttachmentImports, HbButtonComponent],
  providers: [provideIcons({ phosphorFilePdf })],
  template: `
    @if (!removed()) {
      <hb-attachment
        class="max-w-sm"
        hbIcon="phosphorFilePdf"
        hbName="autumn-walk.pdf"
        hbDescription="248 KB · PDF"
        hbRemovable
        (hbRemove)="removed.set(true)"
      />
    } @else {
      <button hb-button hbType="outline" hbSize="sm" (click)="removed.set(false)">Restore</button>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAttachmentBasicComponent {
  protected readonly removed = signal(false);
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbAttachmentImports } from '@herbst/ui';

function plate(color: string): string {
  return (
    'data:image/svg+xml,' +
    encodeURIComponent(
      "<svg xmlns='http://www.w3.org/2000/svg' width='160' height='160'>" +
        "<rect width='160' height='160' fill='" +
        color +
        "'/></svg>",
    )
  );
}

@Component({
  selector: 'hb-demo-attachment-gallery',
  imports: [HbAttachmentImports],
  template: `
    <hb-attachment-group class="max-w-xl flex-wrap">
      @for (item of items; track item.name) {
        <hb-attachment
          hbOrientation="vertical"
          class="w-40"
          [hbSrc]="item.src"
          [hbName]="item.name"
          hbDescription="image"
          hbRemovable
        />
      }
    </hb-attachment-group>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAttachmentGalleryComponent {
  protected readonly items = [
    { name: 'oak-leaves.jpg', src: plate('#A64B2A') },
    { name: 'misty-forest.png', src: plate('#6B7A55') },
    { name: 'chestnuts.webp', src: plate('#C79A4E') },
  ];
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorDownloadSimple } from '@ng-icons/phosphor-icons/regular';

import { HbAttachmentImports, HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-attachment-interactive',
  imports: [HbAttachmentImports, HbButtonComponent, NgIcon],
  providers: [provideIcons({ phosphorDownloadSimple })],
  template: `
    <div class="flex w-full max-w-sm flex-col gap-3">
      <hb-attachment
        hbClickable
        hbName="falling-leaves.jpg"
        hbDescription="Click to preview"
        (hbClick)="opened.set(opened() + 1)"
      >
        <button hb-button hbType="ghost" hbSize="icon" hbAttachmentAction aria-label="Download">
          <ng-icon name="phosphorDownloadSimple" />
        </button>
      </hb-attachment>

      <hb-attachment hbDisabled hbName="archived.zip" hbDescription="Disabled — no interaction" />

      <p class="font-mono text-[12px] text-muted-foreground">Opened {{ opened() }}×</p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAttachmentInteractiveComponent {
  protected readonly opened = signal(0);
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbAttachmentImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-attachment-sizes',
  imports: [HbAttachmentImports],
  template: `
    <hb-attachment-group hbOrientation="vertical" class="w-full max-w-sm">
      <hb-attachment hbSize="xs" hbName="xs.pdf" hbDescription="extra small" />
      <hb-attachment hbSize="sm" hbName="sm.pdf" hbDescription="small" />
      <hb-attachment hbSize="md" hbName="md.pdf" hbDescription="medium" />
      <hb-attachment hbSize="lg" hbName="lg.pdf" hbDescription="large" />
      <hb-attachment hbSize="xl" hbName="xl.pdf" hbDescription="extra large" />
    </hb-attachment-group>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAttachmentSizesComponent {}
